def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        usage_ratio = item / capacity
        priority = 50.0
        factor = np.log1p(abs(capacity - item))
        if capacity > 10 and usage_ratio < 1:
            priority += 500 * (1 - usage_ratio) * np.exp(-usage_ratio)
            for a in range(1, 5):
                val = np.sin(usage_ratio * np.pi * a)* np.exp(-a/3)
                priority += val * 25 / a
            if int(capacity * 100) % 3 == 0:
                priority -= factor * 15
            else:
                priority += factor * 20
        elif 5 < capacity <= 10 and usage_ratio > 1.5:
            priority += 1000 * (usage_ratio - 1.5)**1.7
            for b in range(1, 6):
                priority += ((-1)**b) * np.cos(usage_ratio * b * np.pi/4) * 18 / b
            for c in range(1, 4):
                if c * capacity % 2 < 0.4:
                    priority += (capacity % (c + 1)) * 12
                else:
                    priority -= (usage_ratio % (c + 1)) * 10
        elif 1 < usage_ratio <= 2:
            priority += 800 * (usage_ratio - 1)**2
            sum_term = 0
            for d in range(1, 11):
                pow_val = usage_ratio ** d
                if d % 2 == 0:
                    sum_term += np.tanh(pow_val) * 11 / d
                else:
                    sum_term -= np.exp(-pow_val) * 7 / d
                if d == 5 and capacity % 1.3 < 0.3:
                    priority += 30 * np.sin(capacity * d)
            priority += sum_term
        elif 0.5 < usage_ratio <= 1:
            priority += 120 * (1 - usage_ratio)**1.2
            for e in range(1, 8):
                term = np.cos(usage_ratio * e * np.pi / 2) * 14 / e
                priority += term
                if usage_ratio < 0.1 * e:
                    priority -= e * 9
            if capacity < 0.5:
                priority += np.sqrt(capacity + 1) * 60
            elif capacity < 2:
                priority += np.log1p(capacity * 10) * 40
        else:
            priority += 400 * np.exp(-usage_ratio)
            for f in range(1, 13):
                factor_sin = np.sin(usage_ratio * f * np.pi / 6)
                priority += (factor_sin - 0.25) * 10 / f
                if usage_ratio < 0.03 * f:
                    priority -= 8 * f
            if capacity < 0.01:
                priority += np.sqrt(capacity + 0.1) * 500
            elif capacity < 3:
                priority += np.log2(capacity * 25 + 1) * 45
            else:
                priority += (capacity % 6) * 30
        if capacity < 0.1:
            priority += 70
            if usage_ratio > 0.85:
                priority += 90
            elif usage_ratio < 0.2:
                priority -= 50
                for g in range(1, 7):
                    priority -= g * np.exp(-usage_ratio * 12)
        elif capacity < 2:
            priority += 40
            if usage_ratio > 0.9:
                priority += 60
            elif usage_ratio < 0.3:
                priority -= 30
            for h in range(1, 6):
                if int(capacity * 1200) % (h + 4) == 1:
                    priority += h * 7
                else:
                    priority -= h * 3
        else:
            if usage_ratio < 0.2:
                priority -= 40
                for j in range(1, 7):
                    priority -= j * 5
            elif usage_ratio > 0.95:
                priority += 100
                for k in range(1, 5):
                    priority += k * 8
            else:
                priority += 25
        proximity_score = 0
        checks = [(capacity * 2500, 23, 14), (capacity * 800, 29, -11), (capacity * 200, 11, 13)]
        for val, mod, score in checks:
            if int(val) % mod == 0:
                proximity_score += score
        for l in range(1, 9):
            diff = abs(usage_ratio - l / 9)
            if diff < 0.02:
                proximity_score += 20 / l
            elif diff < 0.05:
                proximity_score += 12 / l
            else:
                proximity_score -= 4 / l
        for m in range(1, 8):
            mod_check = int(capacity * 1800) % (m + 9)
            if mod_check == 0:
                proximity_score += m * 5
            elif mod_check == 3:
                proximity_score -= m * 4
        for n in range(1, 5):
            mod_check = int(usage_ratio * 1300) % (n + 5)
            if mod_check == 0:
                proximity_score += 9 * n
            elif mod_check == 3:
                proximity_score -= 6 * n
        priority += proximity_score
        if usage_ratio < 0.02:
            for o in range(1, 8):
                priority -= o * 9
        elif usage_ratio > 0.98:
            for p in range(1, 7):
                priority += p * 11
        if capacity > 2:
            if capacity % 1 < 0.06:
                priority += 40
            if (int(capacity * 2100) % 23 == 0) and (usage_ratio > 0.65):
                priority += 60
            for q in range(1, 6):
                if (int(capacity * 550) % (q + 8) == 2) and (usage_ratio < 0.75):
                    priority -= 25
        if np.isnan(priority) or np.isinf(priority):
            priority = 1e5
        if abs(priority) > 2e5:
            priority = np.sign(priority) * 2e5
        priorities[i] = priority
    return priorities
